export type HarthmereLicensedClothingLicense = {
  id: string;
  title: string;
  author: string;
  authorUrl: string;
  sourceUrl: string;
  license: string;
  licenseUrl: string;
  creditRequired: boolean;
  commercialUseAllowed: boolean;
  creditLine: string;
  notes?: string;
};

