export const HARTHMERE_ROLE_LICENSED_CLOTHING_DEFAULTS: Record<string, readonly string[]> = HARTHMERE_ROLE_LICENSED_CLOTHING_DEFAULTS_INTERNAL;

export function getHarthmereLicensedClothingById(id: string): HarthmereLicensedClothingItem | undefined {
  return HARTHMERE_LICENSED_CLOTHING_ASSETS.find((item) => item.id === id);
}

export type HarthmereLicensedRoleClothingOptions = {
  gender?: "male" | "female" | "neutral";
  style?: "peasant" | "ranger" | "any";
  includeCreditRequiredAssets?: boolean;
  includeReferenceOnlyAssets?: boolean;
};

export function getHarthmereLicensedClothingForRole(
  role: string,
  options: HarthmereLicensedRoleClothingOptions = {}
): HarthmereLicensedClothingItem[] {
  const normalizedRole = (role || "townsperson").toLowerCase();
  const ids = HARTHMERE_ROLE_LICENSED_CLOTHING_DEFAULTS[normalizedRole] || HARTHMERE_ROLE_LICENSED_CLOTHING_DEFAULTS.townsperson || [];
  const gender = options.gender;
  const style = options.style ?? "any";

  return ids
    .map((id: string) => getHarthmereLicensedClothingById(id))
    .filter((item): item is HarthmereLicensedClothingItem => Boolean(item))
    .filter((item: HarthmereLicensedClothingItem) => item.enabledByDefault || options.includeReferenceOnlyAssets)
    .filter((item: HarthmereLicensedClothingItem) => {
      const license = HARTHMERE_CLOTHING_ASSET_LICENSES[item.licenseId];
      return !license?.creditRequired || options.includeCreditRequiredAssets || item.licenseId === "quaternius_fantasy_standard";
    })
    .filter((item: HarthmereLicensedClothingItem) => !gender || item.tags?.includes(gender) || item.tags?.includes("neutral"))
    .filter((item: HarthmereLicensedClothingItem) => style === "any" || item.tags?.includes(style));
}

export function mergeHarthmereLicensedClothingForRole<T extends { id?: string }>(
  existing: T[] | undefined,
  role: string,
  options: HarthmereLicensedRoleClothingOptions = {}
): Array<T | HarthmereLicensedClothingItem> {
  const base = Array.isArray(existing) ? existing : [];
  const seen = new Set(base.map((item: any) => item?.id).filter(Boolean));
  const additions = getHarthmereLicensedClothingForRole(role, options).filter((item: HarthmereLicensedClothingItem) => !seen.has(item.id));
  return [...base, ...additions];
}

export function getHarthmereClothingCreditLinesForItemIds(itemIds: readonly string[]): string[] {
  const licenseIds = new Set<string>();

  for (const id of itemIds) {
    const item = getHarthmereLicensedClothingById(id);
    if (item) {
      licenseIds.add(item.licenseId);
    }
  }

  return Array.from(licenseIds)
    .map((licenseId) => HARTHMERE_CLOTHING_ASSET_LICENSES[licenseId])
    .filter((license): license is HarthmereLicensedClothingLicense => Boolean(license))
    .filter((license) => license.creditRequired)
    .map((license) => license.creditLine);
}
